INSERT INTO education_data.education_data VALUES ('Ы', 'Тотьма', 'Europe/Moscow', 'ул Советская,д 34', NULL, 'обл Вологодская,р-н Тотемский,г Тотьма,ул Советская,д 34', '{"type": "Point", "coordinates": [42.76816587368011, 59.973877845196604]}', '<p>МБОУ ДО "Петровская ДХШ" - учреждение дополнительного образования в сфере культура,  проводит обучение по общеразвивающим программам изобразительного и декоративно-прикладного искусства и проедпрофессиональной программме "Живопись".  Основной контингент учащиеся в возрасте с 6 до 18 лет.  В школе работают отделения: 1. подготовительное для учащихся в возрасте с 6 до 10 лет, где дети приобретиют навыки лепки и изобразительного искусства, 2. ремесленное отделение, возраст учащихся 10-14 лет, постигают азы ремесленного дела: керамика, резьба и роспись по дереву, композиция. 3. отделение "Живопись", занимаются по одноименной предпрофессиональной программе дети в возрасте с 10 до 15 лет 4. отделение ранней профориентации для учащихся старшего возраста, закончивших основные отделения школы.  В выставочном зале школы организует тематические выставки и проводит экскурсии для учащихся образовательных учреждений, воспитанников детских садов, жителей и гостей г. Тотьма.</p>', 'https://s22307.edu35.ru/', 'pdhshkolatotma@yandex.ru', '[{"value": "78173921774"}, {"value": "78173921774"}]', '{"url": "https://all.culture.ru/uploads/0e423972d18d314643e370a13fbb096d.jpg", "title": "здание ПДХШ.jpg"}', '[{"url": "https://all.culture.ru/uploads/b78e400d5aef14cde202ffbf72ff2a38.jpg", "title": "5.jpg"}, {"url": "https://all.culture.ru/uploads/eca14b05000cf159f19eea01ce9f082a.jpg", "title": "6.jpg"}, {"url": "https://all.culture.ru/uploads/d63a0e1cc9a131b64ab5cab9d7de3bbf.jpg", "title": "11.jpg"}, {"url": "https://all.culture.ru/uploads/038b747a6772ccc3bbd4dad1d09f2ecf.jpg", "title": "8.jpg"}]', NULL, 'Образовательные учреждения', 'МБОУ ДОД «Петровская ДХШ»', 'Тотьма', 'Europe/Moscow', 'ул Советская,д 34', NULL, 'обл Вологодская,р-н Тотемский,г Тотьма,ул Советская,д 34', NULL, 3518003486, 'othergov', 'Тотемский район', 'Europe/Moscow', NULL, 17421, '[{"id": 21, "name": "Выставочные залы", "sysName": "vystavochnye-zaly"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 67359, '[{"url":"https://www.culture.ru/institutes/80748/uchebnyi-korpus-mbou-do-petrovskaya-dkhsh","serviceName":"Культура.рф"}]', NULL, NULL, NULL, NULL, '2022-03-29 09:18:22+03', '2022-04-08 15:53:34+03', '0101000020E6100000FFAD6442536245408DB57B07A8FC4D40');
INSERT INTO education_data.education_data VALUES ('Детская школа искусств «Гармония» г. Череповца', 'Череповец', 'Europe/Moscow', 'ул Архангельская,д 15Б', 'Автобусы №: 2, 7, 9, 12, 18, 31, 38', 'обл Вологодская,г Череповец,ул Архангельская,д 15Б', '{"type": "Point", "coordinates": [37.975758, 59.121393]}', '<p> Муниципальное автономное учреждение «Детская школа искусств «Гармония» (ранее «Детская музыкальная школа № 4») основана в 1962 году. Приказом управления по делам культуры областного исполнительного комитета от 14 февраля 1962 года на базе единственной на тот момент «Детской музыкальной школы № 1» была открыта новая «Вечерняя подростковая музыкальная школа». 19 августа 1975 года приказом отдела культуры г. Череповца «Вечерняя подростковая музыкальная школа» становится «Детской музыкальной школой № 4». Постановлением мэра г. Череповца от 30 августа 2006 года в связи с открытием хореографического отделения и отделения эстетического образования «Детская музыкальная школа № 4» переименована в «Детскую школу искусств «Гармония». </p><p>В учреждении функционируют 6 отделений – теоретическое, фортепианное, хореографическое, вокально-хоровое, отделения народных, струнно-смычковых, духовых и ударных инструментов, на которых ведется обучение по 26 специальностям и направлениям: фортепиано, баян, аккордеон, домра, гитара, балалайка, флейта, кларнет, саксофон, скрипка, виолончель, синтезатор, академическое пение, эстрадное пение, хоровое пение, хореографическое искусство, общее эстетическое образование и раннее эстетическое образование. В школе ведется обучение детей с 3-летнего возраста, возможно индивидуальное обучение не только детей, но и взрослых по любому выбранному учебному предмету.</p><p>Ежегодно в школе учатся около 600 детей и подростков. </p> <p></p>', 'http://garmoniya.vlg.muzkult.ru', 'music-school4@mail.ru', '[{"value": "78202289078", "comment": ""}, {"value": "78202289076", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/d24c239be5dba6e0167d3137373a1d8b.jpg", "title": "Гармония Осенью.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская школа искусств «Гармония»', 'Череповец', 'Europe/Moscow', 'ул Архангельская,д 15', NULL, 'обл Вологодская,г Череповец,ул Архангельская,д 15', NULL, 3528037406, 'mincult', 'Череповец', 'Europe/Moscow', NULL, 20177, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 61289, '[{"url":"https://www.culture.ru/institutes/61808/detskaya-shkola-iskusstv-garmoniya-g-cherepovca","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/85994pl","serviceName":"Афиша7"}]', NULL, NULL, NULL, NULL, '2022-02-08 18:01:53+03', '2022-11-16 12:51:49+03', '0101000020E6100000BA675DA3E5FC42404E7B4ACE898F4D40');
INSERT INTO education_data.education_data VALUES ('Средняя общеобразовательная школа № 17 г. Череповца', 'Череповец', 'Europe/Moscow', 'ул Космонавта Беляева,д 48', 'авт. № 18', 'обл Вологодская,г Череповец,ул Космонавта Беляева,д 48', '{"type": "Point", "coordinates": [38.006489, 59.123767]}', '<p><span>Средняя общеобразовательная школа № 17 открылась 1 сентября 1987 года. </span><span>В ней обучаются 1 428 человек в 48 классах. Начальная школа состоит из 21 класса, основная и средняя школа – из 27 классов.</span><span></span></p><p><span>В школе действуют кружки дополнительного образования детей различных направлений: </span><span>«</span><span>Python </span><span>для начинающих»</span>, <span>«Занимательный квиллинг»</span>, <span>«Роботехника (</span><span>Lego</span><span> </span><span>WeDo</span><span> 2.0)» </span>, <span>«Роботехника (</span><span>Lego</span><span> </span><span>Mindstorms</span><span>)», </span><span>«Мультстудия», «Тележурналистика», «PROдвижение», «Медиаlab», «Медиатворчество», «В объективе», «Видеоблогинг», «Безопасность в соцсетях», «Мир творчества», «Волейбол», «Скоро в школу», «Мой первый английский» и др.</span><br /></p> <p><span></span> В августе 2022 года в школе открылся первый в городе медиацентр «Медиаточка». </p><p>В актовом зале учреждения проводятся праздники, семинары, конференции, конкурсы.</p>', 'http://www.school17.hostedu.ru', 'school17@cherepovetscity.ru', '[{"value": "79922899976", "comment": ""}, {"value": "78202282015", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/bb8ef3903c4eab1778206ef84b21897d.jpg", "title": "17.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАОУ «СОШ № 17»', 'Череповец', 'Europe/Moscow', 'ул Космонавта Беляева,д д 48', NULL, 'обл Вологодская,г Череповец,ул Космонавта Беляева,д д 48', NULL, 3528068193, 'othergov', 'Череповец', 'Europe/Moscow', NULL, 34091, '[{"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "16:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 74652, '[{"url":"https://www.culture.ru/institutes/87661/srednyaya-obsheobrazovatelnaya-shkola-17-g-cherepovca","serviceName":"Культура.рф"}]', NULL, NULL, NULL, NULL, '2023-01-07 11:07:38+03', '2023-01-10 08:26:37+03', '0101000020E61000005264ADA1D40043407AA9D898D78F4D40');
INSERT INTO education_data.education_data VALUES ('Тотемская детская музыкальная школа', 'Тотьма', 'Europe/Moscow', 'ул Белоусовская,д 30', NULL, 'обл Вологодская,р-н Тотемский,г Тотьма,ул Белоусовская,д 30', '{"type": "Point", "coordinates": [42.759843, 59.97305]}', '<p> <span>Дата создания – 1 августа 1962 года. Алла Ивановна Грачева, назначенная директором, сумела заложить традиции школы, посвятив себя музыкально-эстетическому воспитанию подрастающего поколения. </span><span>С 2003 года по 2013 год школу возглавляла Татьяна Вячеславовна Мишина. Она стремилась сохранить сложившиеся в школе традиции. 5 выпускников ее класса работают преподавателями в музыкальной школе.<span> </span>С 2014 года школу возглавляет Любовь Николаевна Зайцева, она смогла поднять проектную деятельность на высокий уровень, укрепить материальную базу. </span></p> <p><span>В школе работают 15 преподавателей, в 2010 году ей присвоена высшая категория. Здесь обучаются 217 детей, работают 10 творческих коллективов: хоры первого класса, хоры младших и старших классов, образцовый художественный коллектив хоровая группа «Радуга», инструментальные коллективы – ансамбль домристов, ансамбль баянистов «Аккорд», ансамбль гитаристов «Созвучие», ансамбль народных инструментов «Мозаика».</span> </p>', 'https://d22305.edu35.ru', 'totmadmsh@mail.ru', '[{"value": "79211445063", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/aa5d243b9018a013f6e6c2060f8dc373.jpg", "title": "Школа.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБОУ ДОД «Тотемская ДМШ»', 'Тотьма', 'Europe/Moscow', 'ул Белоусовская,д 30', NULL, 'обл Вологодская,р-н Тотемский,г Тотьма,ул Белоусовская,д 30', NULL, 3518002267, 'mincult', 'Тотьма', 'Europe/Moscow', NULL, 16711, '[{"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}, {"id": 194, "name": "Дополнительное образование", "sysName": "dopolnitelnoe-obrazovanie"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78911, '[{"url":"https://www.culture.ru/institutes/91767/totemskaya-detskaya-muzykalnaya-shkola","serviceName":"Культура.рф"}]', NULL, NULL, NULL, NULL, '2023-04-11 15:32:11+03', '2023-04-17 08:47:12+03', '0101000020E6100000198C118942614540B8AF03E78CFC4D40');
INSERT INTO education_data.education_data VALUES ('Череповецкая районная детская школа искусств', 'Череповецкий район', 'Europe/Moscow', 'ул Рабочая,д 11', NULL, 'обл Вологодская,р-н Череповецкий,п Тоншалово,ул Рабочая,д 11', '{"type": "Point", "coordinates": [37.947389, 59.192905]}', '<p>В 1979 году была открыта детская музыкальная школа, в которой дети начали обучаться игре на баяне, аккордеоне и фортепиано. С 1 января 1990 года школа получила статус Череповецкой районной школы искусств. </p> <p> </p> <p>В настоящее время в школе функционируют 5 отделений: музыкальное; художественное; театральное; отделение общего эстетического образования; отделение раннего эстетического образования.</p><p> </p> <p> </p> <p>Учреждение активно ведет работу по обеспечению открытости образовательного пространства. В школе сформирована система <span>ранней профессиональной ориентации</span> учащихся. <span>Череповецкая районная детская школа искусств является учебно-методической площадкой «История и культура Череповецкого района в творчестве учащихся школы искусств».</span></p>', NULL, NULL, NULL, '{"url": "https://all.culture.ru/uploads/9a1610a8cc6353a1236de5abe8ad8acc.jpg", "title": "6jAyRkUCjTE.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «Череповецкая Районная Детская Школа Искусств»', 'Череповецкий район', 'Europe/Moscow', 'ул Рабочая,д д 11', NULL, 'обл Вологодская,р-н Череповецкий,п Тоншалово,ул Рабочая,д д 11', NULL, 3523007341, 'mincult', 'Череповецкий район', 'Europe/Moscow', NULL, 34681, '[{"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 26, "name": "Современное искусство", "sysName": "sovremennoe-iskusstvo"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "17:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78242, '[{"url":"https://www.culture.ru/institutes/91130/cherepoveckaya-raionnaya-detskaya-shkola-iskusstv","serviceName":"Культура.рф"}]', NULL, NULL, NULL, NULL, '2023-03-27 16:36:13+03', '2023-03-29 10:19:12+03', '0101000020E61000008ACBF10A44F94240111E6D1CB1984D40');
INSERT INTO education_data.education_data VALUES ('Бабаевская детская школа искусств', 'Бабаевский район', 'Europe/Moscow', 'ул Гайдара,д 25', NULL, 'обл Вологодская,р-н Бабаевский,г Бабаево,ул Гайдара,д 25', '{"type": "Point", "coordinates": [35.93395104495239, 59.40388943849782]}', '<p>Бабаевская школа искусств открылась в 1965 году. </p><p>В настоящее время в школе работают отделения: </p><ul><li>музыкальное (направления – фортепиано, скрипка, баян);</li><li> хореографическое;</li><li> изобразительного искусства, включая отделение в с. Борисово-Судском;</li><li> вокальное;</li><li> платных образовательных услуг (программы «Раннее эстетическое развитие», «Боди-балет» – хореография для взрослых, «Школа живописи» для взрослых).</li></ul><p>Сроки обучения в школе различны – от 9 месяцев до 8 лет, обучаются дети дошкольного и школьного возраста. Педагогический коллектив – 23 преподавателя, почти половину из них составляют молодые педагоги. </p><p>Школа гордится своими выпускниками. Многие из них выбрали своей профессией музыку и педагогику. Высокий профессионализм педагогов, их постоянное стремление к совершенствованию собственного педагогического мастерства, общая нацеленность коллектива на результат отражаются на качестве учебного процесса, которое постоянно повышается. Регулярно обучающиеся занимают призовые места, участвуя в конкурсах, викторинах, олимпиадах, творческих марафонах различного уровня – от районного до международного. </p><p>В течение года школа живет насыщенной жизнью – организуются концерты, выставки, экскурсии, праздники для детей и родителей. Созданы и плодотворно работают творческие коллективы.</p>', 'http://dshi-babaevo.vlg.muzkult.ru', 'babaevodsi2012@yandex.ru', '[{"value": "79211261824", "comment": ""}, {"value": "79215486101", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/6414aeadaf60868089ac0048d05c73af.jpg", "title": "VRSxx14gGEI.jpg"}', '[{"url": "https://all.culture.ru/uploads/c4e4282dc350e6699f4b3210504b6760.jpg", "title": "Ayk6k_eduCw.jpg"}, {"url": "https://all.culture.ru/uploads/e2adb260c22898902962e484c39a04ed.jpg", "title": "f76bhYkz2nI.jpg"}, {"url": "https://all.culture.ru/uploads/bc3394fdb31a66d7769345a126fba85c.jpg", "title": "-aoovxjPILs.jpg"}, {"url": "https://all.culture.ru/uploads/3513babd49487548a0d64ba7c9e1f566.jpg", "title": "vEUSoaKz7Cg.jpg"}, {"url": "https://all.culture.ru/uploads/fd96808ee3ada0a53e4bc3654b519a90.jpg", "title": "lFyD3gQQHYo.jpg"}, {"url": "https://all.culture.ru/uploads/b22769f8656176b367faf3c96ce50660.jpg", "title": "vkYgXd07SjQ.jpg"}, {"url": "https://all.culture.ru/uploads/ef7177a688d128d5287ea2f6cef429f2.jpg", "title": "FLUznsMKcEk.jpg"}]', NULL, 'Образовательные учреждения', 'МАУ ДО «Бабаевская ДШИ»', 'Бабаевский район', 'Europe/Moscow', 'ул Гайдара,д 25', NULL, 'обл Вологодская,р-н Бабаевский,г Бабаево,ул Гайдара,д 25', NULL, 3501004795, 'mincult', 'Бабаевский район', 'Europe/Moscow', '[{"network":"vk","name":"Алёна Сосунова","networkId":"10523720","updateDate":"2023-04-11T12:56:39Z","createDate":"2023-04-11T12:56:39Z","accountId":47087,"postingGroupId":41664},{"network":"vk","name":"Бабаевская детская школа искусств","networkId":"114241035","updateDate":"2023-04-11T12:56:24Z","createDate":"2023-04-11T12:56:24Z","accountId":47087,"postingGroupId":41663}]', 20444, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}, {"id": 194, "name": "Дополнительное образование", "sysName": "dopolnitelnoe-obrazovanie"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 751, "name": "Культура для школьников", "sysName": "kultura-dlya-shkolnikov"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 68488, '[{"url":"https://www.culture.ru/institutes/81734/babaevskaya-detskaya-shkola-iskusstv","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/babaevo/obrazovatelnye-uchrezhdeniya/75794pl","serviceName":"Афиша7"}]', NULL, NULL, NULL, NULL, '2022-04-13 12:47:22+03', '2023-04-12 09:57:46+03', '0101000020E6100000591135B58BF7414023C62CA6B2B34D40');
INSERT INTO education_data.education_data VALUES ('Кирилловская детская школа искусств', 'Кирилловский район', 'Europe/Moscow', 'ул Гагарина,д 108', NULL, 'обл Вологодская,р-н Кирилловский,г Кириллов,ул Гагарина,д 108', '{"type": "Point", "coordinates": [38.37444866137697, 59.859980924307166]}', '<p style="margin-left:0px">Школа открыта в сентябре 1961 года. <span>Это было знаменательным событием для города: кирилловские дети получили возможность развивать свои музыкальные способности, обучаться игре на разных инструментах, приобщаться к миру серьезной музыки. </span><span></span>В 1992 году школа была переименована в детскую школу искусств. </p><p style="margin-left:0px">В настоящее время Кирилловская детская школа искусств реализует дополнительные предпрофессиональные и общеразвивающие общеобразовательные программы художественно-эстетической направленности на следующих отделениях:</p><ul><li>музыкальное: фортепиано, гармонь, гитара;</li><li>художественное и декоративно-прикладное;</li><li>хореографическое;</li><li>раннее эстетическое обучение.</li></ul>', 'https://kdshi.vlg.muzkult.ru', 'dwi-kirillov@mail.ru', '[{"value": "78175731312"}]', '{"url": "https://all.culture.ru/uploads/07ce8e8753e9412e76c45ec163b6a08c.jpg", "title": "20230606_124658.jpg"}', NULL, NULL, 'Образовательные учреждения', 'БУДО «Кирилловская ДШИ»', 'Кирилловский район', 'Europe/Moscow', 'ул Гагарина,д 108', NULL, 'обл Вологодская,р-н Кирилловский,г Кириллов,ул Гагарина,д 108', NULL, 3511002370, 'mincult', 'Кирилловский район', 'Europe/Moscow', NULL, 35338, '[{"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}, {"id": 122, "name": "Искусство", "sysName": "iskusstvo"}, {"id": 194, "name": "Дополнительное образование", "sysName": "dopolnitelnoe-obrazovanie"}, {"id": 317, "name": "Для молодежи", "sysName": "dlya-molodezhi"}, {"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}, {"id": 751, "name": "Культура для школьников", "sysName": "kultura-dlya-shkolnikov"}]', NULL, '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', '{"to": "19:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 79986, '[{"url":"https://www.culture.ru/institutes/92977/kirillovskaya-detskaya-shkola-iskusstv","serviceName":"Культура.рф"}]', NULL, NULL, NULL, NULL, '2023-06-20 14:36:44+03', '2023-06-20 16:17:59+03', '0101000020E6100000915209EFED2F4340A48ADCDA13EE4D40');
INSERT INTO education_data.education_data VALUES ('Центр образования им. И. А. Милютина', 'Череповец', 'Europe/Moscow', 'ул Монтклер,д 12А', NULL, 'обл Вологодская,г Череповец,ул Монтклер,д 12А', '{"type": "Point", "coordinates": [37.926566, 59.088165]}', '<p>Центр образования имени Ивана Андреевича Милютина – уникальное инновационное образовательное учреждение, созданное в 1990 году. В 2019 году у него появилось новое здание площадью более 33 000 кв. м.</p><p>Здесь созданы условия для проведения разнообразных образовательных, культурных, массовых и спортивных мероприятий: учебные классы, 2 актовых зала, оборудованных современной звуковой техникой, спортивные залы, холлы и рекреации.</p> <p>Изюминкой учреждения является уникальная зона релаксации, в которой находится парадная лестница с местами для сидения – место прекрасно подходит для проведения мероприятий любого формата. Есть множество пространств для организации и проведения выставок.</p>', 'https://milytin.ru/sp-shkola-23', 'school8@cherepovetcity.ru', '[{"value": "78202595527", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/3a121d43390a494a532cf4a16046838e.jpg", "title": "6_VO (10).jpg"}', '[{"url": "https://all.culture.ru/uploads/86a4ed37b7f6ce1e864bc4aa9bf20f7a.jpeg", "title": "WhatsApp Image 2019-08-15 at 16.22.50 (1).jpeg"}, {"url": "https://all.culture.ru/uploads/a450853b1ab51c9eab1f33f170e2b57f.jpeg", "title": "WhatsApp Image 2019-08-15 at 16.22.52.jpeg"}, {"url": "https://all.culture.ru/uploads/738c07d68721fb2d3efe1af534209194.jpeg", "title": "WhatsApp Image 2019-08-15 at 16.22.48.jpeg"}, {"url": "https://all.culture.ru/uploads/5429ed960a79ac59ef9c0226fb8043d9.jpeg", "title": "WhatsApp Image 2019-08-15 at 16.22.50.jpeg"}]', NULL, 'Образовательные учреждения', 'МАОУ «ЦО им. И.А. Милютина»', 'Череповец', 'Europe/Moscow', 'ул Матуринская,д д 58', NULL, 'обл Вологодская,г Череповец,ул Матуринская,д д 58', NULL, 3528045478, 'othergov', 'Череповец', 'Europe/Moscow', NULL, 33689, '[{"id": 596, "name": "Доступная среда", "sysName": "dostupnaya-sreda"}]', NULL, '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73656, '[{"url":"https://www.culture.ru/institutes/86663/centr-obrazovaniya-im-i-a-milyutina","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/89000pl","serviceName":"Афиша7"}]', NULL, NULL, NULL, NULL, '2022-12-01 17:51:43+03', '2023-08-03 11:44:39+03', '0101000020E6100000F3CAF5B699F642406FD39FFD488B4D40');
INSERT INTO education_data.education_data VALUES ('Детская художественная школа им. В. Н. Корбакова г. Вологды', 'Вологда', 'Europe/Moscow', 'пр-кт Советский,д 54', NULL, 'обл Вологодская,г Вологда,пр-кт Советский,д 54', '{"type": "Point", "coordinates": [39.901278, 59.213289]}', '<p> Вологодская детская художественная школа открылась 1 сентября 1967 года. Первыми преподавателями были С. . Романова, В. Пелин, А. Кротова, Н. Воздвиженский, М. Никифоров, В. Лугинина, Т. Зибрина. Первые выпускники школы уже вошли в историю культуры Вологодской области и за ее пределами. Это Г. Беккер, Ю. Воронов, Ю. Коробов, Е. Молев, А. Толстов и многие другие. За 45 лет школа выпустила 4 193 учеников.</p> <p>Детская художественная школа им. В. Н. Корбакова реализует программы дополнительного образования в области искусств по предметам: рисунок, живопись, станковая композиция, декоративно-прикладная композиция, история искусства, скульптура, пленэр. Она ведет деятельность для всестороннего развития личности, для подготовки наиболее одаренных учеников к поступлению в учреждения среднего и высшего профессионального образования в сфере искусства и культуры. </p>', NULL, NULL, '[]', '{"url": "https://all.culture.ru/uploads/27636f0050c7985882ce6f0eccec0f05.jpg", "title": "DSC_3472.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Художественная школа им. В. Н. Корбакова г. Вологды»', 'Вологда', 'Europe/Moscow', 'пр-кт Советский,д 54', NULL, 'обл Вологодская,г Вологда,пр-кт Советский,д 54', NULL, 3525086130, 'control', 'Вологда', 'Europe/Moscow', NULL, 20440, '[{"id": 21, "name": "Выставочные залы", "sysName": "vystavochnye-zaly"}, {"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 26, "name": "Современное искусство", "sysName": "sovremennoe-iskusstvo"}, {"id": 27, "name": "Декоративно-прикладное искусство", "sysName": "dekorativno-prikladnoe-iskusstvo"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}, {"id": 194, "name": "Дополнительное образование", "sysName": "dopolnitelnoe-obrazovanie"}]', NULL, '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', '{"to": "20:00:00", "from": "10:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 81159, '[{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/105889pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/94159/detskaya-khudozhestvennaya-shkola-im-v-n-korbakova-g-vologdy","serviceName":"Культура.рф"}]', NULL, NULL, NULL, NULL, '2023-10-12 09:20:21+03', '2023-10-12 11:44:29+03', '0101000020E6100000594DD7135DF343405CCCCF0D4D9B4D40');
INSERT INTO education_data.education_data VALUES ('Средняя общеобразовательная школа № 14 г. Череповца', 'Череповец', 'Europe/Moscow', 'ул Городецкая,д 20', NULL, 'обл Вологодская,г Череповец,ул Городецкая,д 20', '{"type": "Point", "coordinates": [37.907369, 59.089006]}', '<p>Дата основания школы – 2000 год. Сегодня средняя общеобразовательная школа № 14 Череповца – это:<br /></p><ul><li> массовые мероприятия для учащихся и их родителей, жителей микрорайона;</li><li> городские соревнования, конкурсы и поединки;</li><li> концерты, посвященные красным и памятным датам календаря;</li><li> школьный фестиваль «Грани таланта»;</li><li> педсоветы, методические семинары, круглые столы, квесты для педагогов;</li><li> заседания органа ученического самоуправления «Лидер-клуб»;</li><li> занятия по программам внеурочной деятельности;</li><li>литературные гостиные;</li><li> выставки декоративно-прикладного творчества;</li><li> тематические флешмобы;</li><li> спектакли и представления учреждений культуры;</li><li> традиционные школьные линейки первого и последнего звонков.</li></ul>', 'https://s11018.edu35.ru', 'school14@cherepovetscity.ru', '[]', '{"url": "https://all.culture.ru/uploads/1d644133f54044ef9cbc76a1bdbe740d.JPG", "title": "IMG_2729.JPG"}', '[{"url": "https://all.culture.ru/uploads/b275b9cab57d0e13000b9b4000f6fa9d.JPG", "title": "IMG_5478.JPG"}, {"url": "https://all.culture.ru/uploads/53cc3ba34a15dea2a098461a9fbe95cf.JPG", "title": "грани таланта 2018.JPG"}, {"url": "https://all.culture.ru/uploads/b08717d7af471e6cdf9bed78a366a665.JPG", "title": "IMG_9362.JPG"}, {"url": "https://all.culture.ru/uploads/892d7b743af026b27e76aa398084e5da.JPG", "title": "DSC_0299.JPG"}, {"url": "https://all.culture.ru/uploads/9cf23f72f2bb6259ddb979fc12f2dd68.JPG", "title": "выступатььь.JPG"}, {"url": "https://all.culture.ru/uploads/44e88d185fb2928753979102fe14ba6c.JPG", "title": "DSC_0715.JPG"}, {"url": "https://all.culture.ru/uploads/3f4828436ead46475cc1fc3b64ab9517.JPG", "title": "5г.JPG"}]', NULL, 'Образовательные учреждения', 'МАОУ «СОШ № 14»', 'Череповец', 'Europe/Moscow', 'ул Городецкая,д д 20', NULL, 'обл Вологодская,г Череповец,ул Городецкая,д д 20', NULL, 3528072104, 'mineduc', 'Череповец', 'Europe/Moscow', NULL, 34450, '[{"id": 25, "name": "Классическое искусство", "sysName": "klassicheskoe-iskusstvo"}, {"id": 26, "name": "Современное искусство", "sysName": "sovremennoe-iskusstvo"}, {"id": 28, "name": "Литература", "sysName": "literatura"}, {"id": 29, "name": "Музыка", "sysName": "muzyka"}, {"id": 39, "name": "Для детей", "sysName": "dlya-detey"}]', NULL, '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "18:00:00", "from": "08:00:00"}', '{"to": "14:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 77208, '[{"url":"https://www.culture.ru/institutes/90086/srednyaya-obsheobrazovatelnaya-shkola-14-g-cherepovca","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/95524pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=76af4bde-14b2-41f7-8323-bec255032f6e&shareType=venue","serviceName":"ФанТам"}]', NULL, NULL, NULL, NULL, '2023-03-01 12:29:31+03', '2024-08-29 13:11:29+03', '0101000020E6100000BE33DAAA24F44240EA92718C648B4D40');
INSERT INTO education_data.education_data VALUES ('Детская школа искусств д. Литега', 'Сокольский район', 'Europe/Moscow', 'д 13', NULL, 'обл Вологодская,р-н Сокольский,д Литега,д 13', '{"type": "Point"}', '<p><span>1 сентября 1973 года в поселке Литега был открыт филиал Кадниковской детской музыкальной школы. </span><span>В 1990 году по решению отдела культуры Сокольского горисполкома школа получила статус самостоятельного учреждения. </span></p><p><span></span><span>1 июля 1995 года Литегская детская музыкальная школа реорганизована в детскую школу искусств. Были открыты новые отделения: художественное и хореографическое. 2 июля 2014 года в ходе реорганизации Литегская школа искусств объединена с Сокольской детской школой искусств. </span><br /></p><p>В школе работают творческие коллективы обучающихся и преподавателей:</p> <ul><li>ансамбль сценического танца Сокольской школы искусств («АСТ»), руководители – В. А. Пчелинцева, В. А. Соколова;</li><li>хобби-группа для взрослых (хореография), руководитель – В. А. Пчелинцева.<br /></li></ul>', 'https://shi-sokol.vlg.muzkult.ru', 'sokol-dshi@yandex.ru', '[{"value": "78173322008", "comment": ""}, {"value": "78173352144", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/2f66f6e85020c3d61396ac0daaa00032.jpg", "title": "ik-_RYYMCHE.jpg"}', NULL, NULL, 'Образовательные учреждения', 'БУ ДО СМО «Сокольская ДШИ»', 'Сокольский район', 'Europe/Moscow', 'ул Советская,д 30', NULL, 'обл Вологодская,р-н Сокольский,г Сокол,ул Советская,д 30', NULL, 3527002930, 'mincult', 'Сокольский район', 'Europe/Moscow', '[{"network":"vk","name":"\"Академия занимательных искусств\"","networkId":"195680821","updateDate":"2023-04-25T09:03:47Z","createDate":"2023-04-25T09:03:47Z","accountId":47338,"postingGroupId":41971},{"network":"vk","name":"ИЗО Сокольская школа искусств","networkId":"186131837","updateDate":"2023-04-25T09:03:39Z","createDate":"2023-04-25T09:03:39Z","accountId":47338,"postingGroupId":41970},{"network":"vk","name":"Сокольская детская школа искусств","networkId":"171839233","updateDate":"2023-04-25T09:03:32Z","createDate":"2023-04-25T09:03:32Z","accountId":47338,"postingGroupId":41969}]', 17279, '[{"name": "Классическое искусство"}, {"name": "Декоративно-прикладное искусство"}, {"name": "Музыка"}, {"name": "Для детей"}, {"name": "Дополнительное образование"}]', NULL, '{"to": "18:00:00", "from": "13:00:00"}', '{"to": "18:00:00", "from": "13:00:00"}', '{"to": "18:00:00", "from": "13:00:00"}', '{"to": "18:00:00", "from": "13:00:00"}', '{"to": "18:00:00", "from": "13:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 77063, '[{"url":"https://www.culture.ru/institutes/89969/detskaya-shkola-iskusstv-d-litega","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/sokol/obrazovatelnye-uchrezhdeniya/94989pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=592cbfd8-5ce8-4cde-be15-656b122a9d13&shareType=venue","serviceName":"ФанТам"}]', 77063, NULL, NULL, NULL, '2023-02-28 09:49:34+03', '2024-11-25 09:27:24+03', NULL);
INSERT INTO education_data.education_data VALUES ('Судская детская школа искусств', 'Череповецкий район', 'Europe/Moscow', 'ул Гагарина,д 18', NULL, 'обл Вологодская,р-н Череповецкий,п Суда,ул Гагарина,д 18', '{"type": "Point"}', '<p>Судская детская школа искусств была открыта в 1970 году. Она реализует дополнительные предпрофессиональные общеобразовательные программы в области изобразительного, музыкального и хореографического искусства для детей в возрасте от 6,5 до 18 лет, а также дополнительные общеразвивающие программы художественной направленности для детей от 4 до 18 лет.</p><p>В учреждении сложились и функционируют несколько творческих коллективов:</p><ul><li>хор младших классов;</li><li>вокальный ансамбль и хор старших классов;</li><li>ансамбль духовых инструментов младших классов «Дударики»;</li><li>ансамбль духовых инструментов старших классов;</li><li> ансамбль баянистов старших классов;</li><li>хореографический ансамбль младших классов «Малинки»;</li><li>хореографический ансамбль старших классов «Веселый каблучок»;</li><li>самодеятельный вокальный ансамбль «Гармония».</li></ul>', NULL, NULL, NULL, '{"url": "https://all.culture.ru/uploads/4a82d387ec4c6cc90f0bf3295a0bf65d.jpg", "title": "20220601_100623.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «Судская детская школа искусств»', 'Череповецкий район', 'Europe/Moscow', 'ул Гагарина,д 18', NULL, 'обл Вологодская,р-н Череповецкий,п Суда,ул Гагарина,д 18', NULL, 3523007408, 'mincult', 'Череповецкий район', 'Europe/Moscow', NULL, 34897, '[{"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:30:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 78303, '[{"url":"https://www.culture.ru/institutes/91187/sudskaya-detskaya-shkola-iskusstv","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/98065pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=a0cd33d0-b5c9-4bbd-9216-59a211063ea7&shareType=venue","serviceName":"ФанТам"}]', 78303, NULL, NULL, NULL, '2023-03-28 17:53:21+03', '2025-02-05 15:28:54+03', NULL);
INSERT INTO education_data.education_data VALUES ('Хореографическая школа «Пируэт»', 'Вологда', 'Europe/Moscow', 'ул Космонавта Беляева,д 10', NULL, 'обл Вологодская,г Вологда,ул Космонавта Беляева,д 10', '{"type": "Point"}', '<p> Детская школа искусств (хореографическая) «Пируэт» действует с 6 октября 2011 года. </p><p> </p><p> </p><p>На базе школы действуют 5 творческих хореографических объединений, в которых занимается более 300 человек: образцовый художественный коллектив студия танца «Фантазия», творческое объединение «Тим Таллер», творческое объединение «Движение», творческое объединение Tanzlab, творческое объединение Breaking Bears. Коллективы являются лауреатами и победителями конкурсов и фестивалей различных уровней.</p><p> </p><p>В школе сохраняются традиции и праздники: участие преподавателей и детей в летних сборах, проводимых в дни летних каникул на базе школы и в летних оздоровительных лагерях; проведение школьных творческих конкурсов и праздников, круглых столов, отчетных концертов на сценических площадках города. </p> <p>Ведется большая концертная деятельность обучающихся и преподавателей. Выступления коллективов украшают многочисленные мероприятия, проводимые в городе и области. Работники учреждения имеют различные награды, почетные грамоты и благодарственные письма главы города Вологды и Департамента культуры и туризма Вологодской области.</p>', 'https://pirouette35.vlg.muzkult.ru', 'pirouette11@mail.ru', '[{"value": "78172731740"}, {"value": "78172732460"}]', '{"url": "https://all.culture.ru/uploads/3f01601bf6ca28e8657eb70a1b90a00e.jpg", "title": "Скриншот 13-11-2024 135123.jpg"}', '[{"url": "https://all.culture.ru/uploads/3a593eaebb5dccc0d48f2a045678a33b.jpg", "title": "yIO7JP11sqw.jpg"}]', NULL, 'Образовательные учреждения', 'МАУ ДО «ДШИ (хореографическая) «Пируэт»', 'Вологда', 'Europe/Moscow', 'ул Космонавта Беляева,10', NULL, 'обл Вологодская,г Вологда,ул Космонавта Беляева,10', NULL, 3525251585, 'mincult', 'Вологда', 'Europe/Moscow', NULL, 20412, '[{"name": "Для детей"}]', NULL, '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "20:30:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 66041, '[{"url":"https://www.culture.ru/institutes/79349/khoreograficheskaya-shkola-piruet","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/126747pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=5b59a975-28f6-4755-94d9-2e2d781ebf0f&shareType=venue","serviceName":"ФанТам"}]', 66041, NULL, NULL, NULL, '2022-03-22 12:17:13+03', '2025-02-17 16:48:26+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств г. Череповец на ул. Наседкина', 'Череповец', 'Europe/Moscow', 'ул Наседкина,д 14А', 'авт. № 7, 18, 25, 32 до ост. «Ул. Наседкина»', 'обл Вологодская,г Череповец,ул Наседкина,д 14А', '{"type": "Point"}', '<p>Обучение детей по программам в области искусства ведется в здании Детской школы искусств на улице Наседкина. Здесь принимают детей в возрасте от 3 до 15 лет для обучения изобразительному искусству, хореографии, академическому пению, игре на аккордеоне, баяне, виолончели, гитаре, домре, кларнете, саксофоне, скрипке, трубе, ударных инструментах, флейте, фортепиано. </p><p>Для проведения массовых мероприятий есть концертный зал. В учреждении созданы все условия для полноценных учебных занятий, кроме того, отделение расположено в большом новом жилом городском массиве, что удобно для ребят, проживающих в Зашекснинском районе.</p>', 'https://dshi-cher.vlg.muzkult.ru', 'dshi@cherepovetscity.ru', '[{"value": "78202557174", "comment": ""}, {"value": "78202310246", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/2f500f82a22b33d55eb842f2c85a6c6a.JPG", "title": "IMG_6347.JPG"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская школа искусств»', 'Череповец', 'Europe/Moscow', 'ул Вологодская,д 3', NULL, 'обл Вологодская,г Череповец,ул Вологодская,д 3', NULL, 3528036650, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская школа искусств г. Череповец","networkId":"6605838","updateDate":"2023-02-27T10:54:31Z","createDate":"2023-02-27T10:54:31Z","accountId":46120,"postingGroupId":40497}]', 20178, '[{"name": "Музыка"}, {"name": "Живопись"}, {"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35324, '[{"url":"https://www.culture.ru/institutes/36674/detskaya-shkola-iskusstv-g-cherepovec-na-ul-nasedkina","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/19299pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=8676c472-9f0b-4ada-8ff7-52c08c52963f&shareType=venue","serviceName":"ФанТам"}]', 35324, NULL, NULL, NULL, '2018-06-28 11:32:26+03', '2025-03-08 13:30:56+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств г. Череповец на ул. Олимпийской', 'Череповец', 'Europe/Moscow', 'ул Олимпийская,д 13', 'авт. № 2, 4, 7, 31, трам. № 4, 8 до ост. «Олимпийская»', 'обл Вологодская,г Череповец,ул Олимпийская,д 13', '{"type": "Point"}', '<p>В 2014 году к детской школе искусств присоединилась детская музыкальная школа № 3 на улице Олимпийской.</p><p>В школе обучение учащихся ведется по следующим дополнительным общеразвивающим программам: фортепиано, струнные инструменты (скрипка, виолончель), народные инструменты (аккордеон, баян, балалайка, домра, гитара), духовые и ударные инструменты (флейта, гобой, кларнет, труба, саксофон, ударные инструменты), академическое пение, эстрадное пение, сроком на 4 года (для детей 8–10 лет) и 4 года (для детей 11–13 лет).</p><p>Здесь работает преподавательский состав с высоким профессиональным уровнем, более 50 процентов педагогов имеют высшую квалификационную категорию.</p>', 'https://dshi-cher.vlg.muzkult.ru', 'dshi@cherepovetscity.ru', '[{"value": "78202557174", "comment": ""}, {"value": "78202268090", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/48fc9bce9d661dd17c7660d0fcfd27db.JPG", "title": "IMG_6346.JPG"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская школа искусств»', 'Череповец', 'Europe/Moscow', 'ул Вологодская,д 3', NULL, 'обл Вологодская,г Череповец,ул Вологодская,д 3', NULL, 3528036650, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская школа искусств г. Череповец","networkId":"6605838","updateDate":"2023-02-27T10:54:31Z","createDate":"2023-02-27T10:54:31Z","accountId":46120,"postingGroupId":40497}]', 20178, '[{"name": "Для детей"}, {"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35323, '[{"url":"https://www.culture.ru/institutes/61354/detskaya-shkola-iskusstv-g-cherepovec-na-ul-olimpiiskoi","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/60905pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=0277478b-0019-443b-a90e-2b9929adc192&shareType=venue","serviceName":"ФанТам"}]', 35323, NULL, NULL, NULL, '2018-06-28 11:28:46+03', '2025-03-07 15:04:52+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств г. Череповца на ул. Вологодской', 'Череповец', 'Europe/Moscow', 'ул Вологодская,д 3', 'ост. «Улица Вологодская», авт. № 1, 2, 8, 18, 31, 37', 'обл Вологодская,г Череповец,ул Вологодская,д 3', '{"type": "Point"}', '<p>Детская школа искусств вот уже более 50 лет открывает свои двери для ребят Череповца. В ней трудится более 70 педагогов. Преподавательский состав с высоким профессиональным уровнем успешно реализует дополнительные предпрофессиональные и общеразвивающие программы в области музыкального искусства. Многие выпускники школы продолжают обучение в средних профессиональных и высших учебных заведениях музыкального профиля, далее успешно выступают на концертных сценах России.</p><p>В современной детской школе искусств обучаются дети с 3 лет на отделениях: музыкальном, хореографическом, художественном, раннего эстетического развития. Обучающиеся активно участвуют в конкурсных мероприятиях, проводимых в рамках школы, области, региона и всей страны. В учреждении широко развита конкурсная и концертная деятельность: проводится множество концертов, конкурсов, фестивалей, выставок.</p><p><span></span></p><p style="margin-left:3.6pt;text-align:justify"><strong><span><strong></strong></span></strong></p>', 'https://dshi-cher.vlg.muzkult.ru', 'dshi@cherepovetscity.ru', '[{"value": "78202557174", "comment": ""}, {"value": "78202556538", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/c76acbc7cc34c974a1eb6a19a957a34a.jpg", "title": "K7mEsOVGDVU.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская школа искусств»', 'Череповец', 'Europe/Moscow', 'ул Вологодская,д 3', NULL, 'обл Вологодская,г Череповец,ул Вологодская,д 3', NULL, 3528036650, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская школа искусств г. Череповец","networkId":"6605838","updateDate":"2023-02-27T10:54:31Z","createDate":"2023-02-27T10:54:31Z","accountId":46120,"postingGroupId":40497}]', 20178, '[{"name": "Для детей"}, {"name": "Дополнительное образование"}, {"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35321, '[{"url":"https://www.culture.ru/institutes/36675/detskaya-shkola-iskusstv-g-cherepovca-na-ul-vologodskoi","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/19298pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=7227736c-0c38-42f9-bc95-4e810f542f77&shareType=venue","serviceName":"ФанТам"}]', 35321, NULL, NULL, NULL, '2018-06-28 11:07:08+03', '2025-03-07 15:06:08+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств № 5 г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Карла Маркса,д 14 корп 3', NULL, 'обл Вологодская,г Вологда,ул Карла Маркса,д 14 корп 3', '{"type": "Point"}', '<p>Детская школа искусств № 5 г. Вологды основана в 1977 году в статусе детской музыкальной школы на базе детской музыкально-хоровой студии. Основатель и первый директор школы – известный в Вологде хормейстер и композитор В. С. Беляков.</p><p>На протяжении многих лет ДШИ № 5 имела ярко выраженный хоровой уклон. Младший и старший хоры, вокальные и хоровые ансамбли «Колокольчик», «Созвучие», «Чудесенки» и «Диво Град», народный коллектив молодежный женский камерный хор «Кантилена» являются визитной карточкой музыкальной школы.</p><p> В ДШИ № 5 создано 12 творческих коллективов – это оркестры и большие ансамбли, кроме них, ежегодно создается до 10 новых музыкальных ансамблей, которые активно выступают на различных концертных мероприятиях и успешно представляют школу на конкурсах и фестивалях.</p><p>Коллектив ДШИ № 5 верен лучшим традициям российского музыкального образования и находится в постоянном поиске современных инновационных образовательных методик.</p><p>Сегодня школа искусств– это юные музыканты и творческие коллективы – лауреаты и дипломанты международных, всероссийских, региональных и городских конкурсов. Кроме того, ДШИ № 5 – это социокультурный центр города Вологды. Преподаватели школы бережно хранят атмосферу тепла, радости и вдохновения, создавая все условия для реализации творческого потенциала юных вологжан.<br /></p><p></p><p><strong> </strong></p><p></p>', 'http://www.dmsh-5.ru', 'dmsh5_08@mail.ru', '[{"value": "78172548092"}]', '{"url": "https://all.culture.ru/uploads/4e7db4d05e15e2edf6f8f5da7d8977fc.jpg", "title": "XXL.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская школа искусств № 5 г. Вологды»', 'Вологда', 'Europe/Moscow', 'ул Карла Маркса', NULL, 'обл Вологодская,г Вологда,ул Карла Маркса', NULL, 3525086123, 'mincult', 'Вологда', 'Europe/Moscow', '[{"network":"vk","name":"Детская школа искусств № 5 г. Вологды","networkId":"81982116","updateDate":"2023-04-20T11:11:43Z","createDate":"2023-04-20T11:11:43Z","accountId":47279,"postingGroupId":41890}]', 20452, '[{"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 66137, '[{"url":"https://www.culture.ru/institutes/79257/detskaya-shkola-iskusstv-5-g-vologdy","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/71933pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=4250e3bd-5c95-47eb-8d31-676b18e4e20c&shareType=venue","serviceName":"ФанТам"}]', 66137, NULL, NULL, NULL, '2022-03-22 15:55:58+03', '2025-04-29 12:39:05+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская музыкальная школа № 1 г. Вологды', 'Вологда', 'Europe/Moscow', 'пр-кт Советский,д 2', NULL, 'обл Вологодская,г Вологда,пр-кт Советский,д 2', '{"type": "Point"}', '<p> Детская музыкальная школа № 1 была основана 1 апреля 1919 года. Она реализует дополнительные предпрофессиональные общеобразовательные программы и дополнительные общеразвивающие общеобразовательные программы в области музыкального искусства. Отделения школы: <span>фортепианное, </span>оркестровое (скрипка, виолончель, духовые инструменты), вокальное (академическое, эстрадное пение), народное (домра, балалайка, гитара, баян, гармонь, аккордеон), теоретическое, раннего эстетического образования.</p><p>Здесь ведут работу 13 творческих коллективов, 7 из которых имеют звание «Образцовый художественный коллектив», 1 – «Народный самодеятельный коллектив». </p>', 'https://music-school1.ru', 'muzschool-1@mail.ru', '[{"value": "78172211381"}]', '{"url": "https://all.culture.ru/uploads/bd0e468073ed81afed2df74209fbb90f.jpeg", "title": "MboSzvY3QhU.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУДО «Детская музыкальная школа №1» г. Вологды', 'Вологда', 'Europe/Moscow', 'пр-кт Советский,д 2', NULL, 'обл Вологодская,г Вологда,пр-кт Советский,д 2', NULL, 3525086099, 'mincult', 'Вологда', 'Europe/Moscow', '[{"network":"vk","name":"Детская музыкальная школа №1 г.Вологда","networkId":"152329659","updateDate":"2019-09-18T12:07:12Z","createDate":"2019-09-18T12:07:12Z","accountId":26819,"postingGroupId":23943}]', 18718, '[{"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 60643, '[{"url":"https://afisha7.ru/vologda/prochee/61386pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/101397/detskaya-muzykalnaya-shkola-1-g-vologdy","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=6819b959-2dad-4ee8-88c9-105135f5fe03&shareType=venue","serviceName":"ФанТам"}]', 60643, NULL, NULL, NULL, '2022-02-02 18:26:08+03', '2025-04-24 09:53:27+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств «Арт-идея» г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Солодунова,д 54', 'авт. № 1, 48, 19, 22, 20', 'обл Вологодская,г Вологда,ул Солодунова,д 54', '{"type": "Point"}', '<p><span> Детская школа искусств «Арт-идея» – одно из ведущих муниципальных учреждений дополнительного образования на территории Вологды. </span><span>Первый учебный год в школе начался 1 сентября 1996 года. </span><br /></p><p>Структура школы включает в себя 4 отделения:</p><ul><li>«Хореографическое искусство» (классический танец, современный танец, бальный танец);</li><li>«Музыкальное искусство» (фортепиано, народные инструменты, струнные инструменты, индивидуальный вокал);</li><li>«Изобразительное искусство» (живопись, декоративно-прикладное искусство);</li><li>«Основы хореографии» (для ребят 3–7 лет).</li></ul><p><span> В 2009 году 2 педагога школы стали победителями Всероссийского конкурса на лучшие программы для детских школ искусств (Москва). Комплексная образовательная программа для отделения классического танца «Совершенству нет предела» и комплексная образовательная программа «Танцуем джаз» получили статус примерных учебных программ Министерства культуры Российской Федерации. <br /></span></p><p><span>ДШИ «Арт-идея» в 2016 году стала победителем общероссийского конкурса «50 лучших детских школ искусств», в 2018 году – победителем областного конкурса «Лучшая образовательная организация дополнительного образования детей». Обучающиеся традиционно являются участниками </span><span>Молодежных дельфийских игр России.</span></p>', 'https://art-idea.vlg.muzkult.ru', 'vdsa-kovaleva@rambler.ru', '[{"value": "78172530390", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/984c486f8977aa96f01cee8f1a94d685.jpg", "title": "XXL (1).jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «ДШИ «Арт-идея» г. Вологды', 'Вологодский район', 'Europe/Moscow', 'Солодунова,54', NULL, 'обл Вологодская,р-н Вологодский,Вологда,Солодунова,54', NULL, 3525075040, 'mincult', 'Вологодский район', 'Europe/Moscow', NULL, 20389, '[{"name": "Классическое искусство"}, {"name": "Музыка"}, {"name": "Искусство"}, {"name": "Доступная среда"}, {"name": "Художественные школы"}]', NULL, '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', '{"to": "21:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 59900, '[{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/71892pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/61271/detskaya-shkola-iskusstv-art-ideya-g-vologdy","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=f55f0b33-a9cc-46c4-a9ba-0939859d401f&shareType=venue","serviceName":"ФанТам"}]', 59900, NULL, NULL, NULL, '2022-01-25 18:38:41+03', '2025-04-29 11:49:21+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская художественная школа № 1 на Шекснинском', 'Череповец', 'Europe/Moscow', 'пр-кт Шекснинский,д 13', NULL, 'обл Вологодская,г Череповец,пр-кт Шекснинский,д 13', '{"type": "Point"}', '<p>История развития Детской художественной школы № 1 берет свое начало в 1969 году, когда небольшой коллектив школы возглавил художник-педагог, энтузиаст и подвижник Сергей Павлович Песков.</p><p>Детская художественная школа № 1 сегодня – одна из крупнейших художественных школ Вологодской области и ведущее учреждение дополнительного образования детей города Череповца. В 2007 году школа стала победителем всероссийского конкурса «Детские школы искусств. Достояние Российского государства» (г. Москва) и вошла в число 100 лучших художественных школ России.</p><p>Сейчас школа имеет три помещения в разных районах города, где обучаются более 800 детей с 5 по 18 лет. Ежегодно в Детскую художественную школу № 1 поступает более 200 учащихся, и их количество постоянно растет. Выпускники школы успешно поступают в высшие и средние профессиональные учебные заведения художественной направленности.</p>', 'https://dhsh1.vlg.muzkult.ru/about', 'cher-artschool@mail.ru', '[{"value": "78202574281", "comment": ""}, {"value": "78202446070", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/1511360ad4d4f16e412676fd42ec301d.jpg", "title": "2550a466-fad4-4dc8-9096-324683b0a388.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская художественная школа №1»', 'Череповец', 'Europe/Moscow', 'ул Парковая,д 44', NULL, 'обл Вологодская,г Череповец,ул Парковая,д 44', NULL, 3528037364, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская художественная школа № 1","networkId":"29099218","updateDate":"2023-03-01T13:09:16Z","createDate":"2023-03-01T13:09:16Z","accountId":36914,"postingGroupId":40631}]', 20179, '[{"name": "Доступная среда"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 38279, '[{"url":"https://www.culture.ru/institutes/39575/detskaya-khudozhestvennaya-shkola-1-na-sheksninskom","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/21090pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=8de40b94-8ad4-471e-9a32-e20646f839c6&shareType=venue","serviceName":"ФанТам"}]', 38279, NULL, NULL, NULL, '2019-04-02 12:13:01+03', '2025-05-13 16:01:17+03', NULL);
INSERT INTO education_data.education_data VALUES ('Центр дополнительного образования г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Чернышевского,д 73', 'Троллейбус № 4, автобус № 14, 28, 36.', 'обл Вологодская,г Вологда,ул Чернышевского,д 73', '{"type": "Point"}', '<p>Центр дополнительного образования детей г. Вологды был создан в ноябре 1992 года. </p><p>Центр сегодня – это многопрофильное учреждение, созданное для разностороннего развития человека с позитивной жизненной позицией, нравственным стержнем, способного ориентироваться в окружающем мире, принимать решения и отвечать за свои поступки, стремящегося к саморазвитию и самореализации. Педагогический коллектив центра – это стабильный творческий коллектив единомышленников с высоким уровнем квалификации. </p><p>В учреждении много традиций: праздники, конкурсы, фестивали, семинары юных поэтов и прозаиков, конференции, выставки изобразительного искусства и декоративно-прикладного творчества. Работа в учреждении организуется через деятельность детских коллективов: школа танца «Вологодские узоры», студия керамики «Синяя птица», студия изобразительного искусства, мастерские художественных ремесел и женского рукоделия.</p>', 'http://dodcenter.edu35.ru', 'goucdod@vologda.ru', '[{"value": "78172543244", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/42415d121fb6f63caad80c4cd7e5c54d.jpg", "title": "Фасад ЦДО 1 - копия.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «ЦДО» г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Чернышевского,д 73', NULL, 'обл Вологодская,г Вологда,ул Чернышевского,д 73', NULL, 3525101491, 'mincult', 'Вологда', 'Europe/Moscow', NULL, 17552, '[{"name": "Творчество"}, {"name": "Доступная среда"}, {"name": "Для молодежи"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35964, '[{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/19635pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/36664/centr-dopolnitelnogo-obrazovaniya-g-vologdy","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=7ed7c8c7-460a-4466-b397-0debf97ba867&shareType=venue","serviceName":"ФанТам"}]', 35964, NULL, NULL, NULL, '2018-09-28 14:00:49+03', '2025-05-16 16:57:32+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская художественная школа № 1 на ул. К. Белова', 'Череповец', 'Europe/Moscow', 'ул Командарма Белова,д 13', NULL, 'обл Вологодская,г Череповец,ул Командарма Белова,д 13', '{"type": "Point"}', '<p>  </p><p>История развития Детской художественной школы № 1 берет свое начало в 1969 году, когда небольшой коллектив школы возглавил художник-педагог, энтузиаст и подвижник Сергей Павлович Песков. </p><p>Детская художественная школа № 1 сегодня – одна из крупнейших художественных школ Вологодской области и ведущее учреждение дополнительного образования детей города Череповца. Детская художественная школа № 1 в 2007 году стала победителем всероссийского конкурса «Детские школы искусств. Достояние Российского государства» (г. Москва) и вошла в число 100 лучших художественных школ России.</p><p>Сейчас школа имеет три помещения в разных районах города, где обучаются более 800 детей с 5 по 18 лет.</p><p>Ежегодно в Детскую художественную школу № 1 поступает более 200 учащихся, и их количество постоянно растет. Выпускники школы успешно поступают в высшие и средние профессиональные учебные заведения художественной направленности.</p>  <p></p><p>В филиале на ул. К. Белова представлены направления: подготовительное отделение, основное отделение, профориентационное отделение, художественно-эстетические группы («Солнечный зайчик»).<br /></p>', 'https://dhsh1.vlg.muzkult.ru/about', 'cher-artschool@mail.ru', '[{"value": "78202574281", "comment": ""}, {"value": "78202281607", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/dbecc95fc62f4c087caffa8ddbb80b7b.jpg", "title": "31_big.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская художественная школа №1»', 'Череповец', 'Europe/Moscow', 'ул Парковая,д 44', NULL, 'обл Вологодская,г Череповец,ул Парковая,д 44', NULL, 3528037364, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская художественная школа № 1","networkId":"29099218","updateDate":"2023-03-01T13:09:16Z","createDate":"2023-03-01T13:09:16Z","accountId":36914,"postingGroupId":40631}]', 20179, '[{"name": "Доступная среда"}, {"name": "Для молодежи"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35701, '[{"url":"https://www.culture.ru/institutes/36668/detskaya-khudozhestvennaya-shkola-1-na-ul-k-belova","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/19501pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=71e13fe1-4bb7-4e37-9b8f-ed5eebd1d45e&shareType=venue","serviceName":"ФанТам"}]', 35701, NULL, NULL, NULL, '2018-08-09 14:41:18+03', '2025-05-13 15:55:43+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская художественная школа № 1 на ул. Набережная', 'Череповец', 'Europe/Moscow', 'ул Набережная,д 43', NULL, 'обл Вологодская,г Череповец,ул Набережная,д 43', '{"type": "Point"}', '<p>  </p><p>История развития Детской художественной школы № 1 берет свое начало в 1969 году, когда небольшой коллектив школы возглавил художник-педагог, энтузиаст и подвижник Сергей Павлович Песков. </p><p>Детская художественная школа № 1 сегодня – одна из крупнейших художественных школ Вологодской области и ведущее учреждение дополнительного образования детей города Череповца. Детская художественная школа № 1 в 2007 году стала победителем всероссийского конкурса «Детские школы искусств. Достояние Российского государства» (г. Москва) и вошла в число 100 лучших художественных школ России.</p><p>Сейчас школа имеет три помещения в разных районах города, где обучаются более 800 детей с 5 по 18 лет.</p><p>Ежегодно в Детскую художественную школу № 1 поступает более 200 учащихся, и их количество постоянно растет. Выпускники школы успешно поступают в высшие и средние профессиональные учебные заведения художественной направленности.</p><p>  Детская художественная школа № 1 сегодня – одна из крупнейших художественных школ Вологодской области и ведущее учреждение дополнительного образования детей города Череповца. Детская художественная школа № 1 в 2007 году стала победителем всероссийского конкурса «Детские школы искусств. Достояние Российского государства» (г. Москва) и вошла в число 100 лучших художественных школ России.</p><p></p><p>В филиале на ул. Набережная представлены направления: подготовительное отделение, основное отделение, художественно-эстетические группы («Капитошка», «Радуга»).</p>', 'https://dhsh1.vlg.muzkult.ru/about', 'cher-artschool@mail.ru', '[{"value": "78202574281", "comment": ""}, {"value": "78202553055", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/bd6cbc2b77da6946748c60e5b323ce16.jpg", "title": "6257.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская художественная школа №1»', 'Череповец', 'Europe/Moscow', 'ул Парковая,д 44', NULL, 'обл Вологодская,г Череповец,ул Парковая,д 44', NULL, 3528037364, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская художественная школа № 1","networkId":"29099218","updateDate":"2023-03-01T13:09:16Z","createDate":"2023-03-01T13:09:16Z","accountId":36914,"postingGroupId":40631}]', 20179, '[{"name": "Доступная среда"}, {"name": "Для молодежи"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35696, '[{"url":"https://www.culture.ru/institutes/36669/detskaya-khudozhestvennaya-shkola-1-na-ul-naberezhnaya","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/19497pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=3cf0a6ef-770c-4f8e-bae4-64a2e7de0ee3&shareType=venue","serviceName":"ФанТам"}]', 35696, NULL, NULL, NULL, '2018-08-09 14:23:30+03', '2025-05-13 16:01:11+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская художественная школа № 1 г. Череповца', 'Череповец', 'Europe/Moscow', 'ул Парковая,д 44', NULL, 'обл Вологодская,г Череповец,ул Парковая,д 44', '{"type": "Point"}', '<p><span>История развития Детской художественной школы № 1 берет свое начало в 1969 году, когда небольшой коллектив школы возг</span><span>лавил художник-педагог, энтузиаст и подвижник Сергей Павлович Песков. </span></p><p>Школа сегодня – одна из крупнейших художественных школ Вологодской области и ведущее учреждение дополнительного образования детей города Череповца. В 2007 году она стала победителем всероссийского конкурса «Детские школы искусств. Достояние российского государства» (г. Москва) и вошла в число 100 лучших художественных школ России.</p><p><span>Сейчас учреждение имеет пять помещений в разных районах города, где обучаются более 900 детей с 5 по 18 лет.</span></p><p><span>Ежегодно в нее поступает более 500 учащихся. Выпускники школы успешно поступают в высшие и средние профессиональные учебные заведения художественной направленности.</span></p>', 'https://dhsh1.vlg.muzkult.ru/about', 'cher-artschool@mail.ru', '[{"value": "78202574281", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/93e291f75a2c7b74def030dbc98f8aa5.jpg", "title": "6258.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МАУ ДО «Детская художественная школа №1»', 'Череповец', 'Europe/Moscow', 'ул Парковая,д 44', NULL, 'обл Вологодская,г Череповец,ул Парковая,д 44', NULL, 3528037364, 'mincult', 'Череповец', 'Europe/Moscow', '[{"network":"vk","name":"Детская художественная школа № 1","networkId":"29099218","updateDate":"2023-03-01T13:09:16Z","createDate":"2023-03-01T13:09:16Z","accountId":36914,"postingGroupId":40631}]', 20179, '[{"name": "Доступная среда"}, {"name": "Для молодежи"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 35308, '[{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/19289pl","serviceName":"Афиша7"},{"url":"https://www.culture.ru/institutes/36676/detskaya-khudozhestvennaya-shkola-1-g-cherepovca","serviceName":"Культура.рф"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=c79c11b4-d926-40f6-a33f-1173d2edd3d3&shareType=venue","serviceName":"ФанТам"}]', 35308, NULL, NULL, NULL, '2018-06-26 17:03:51+03', '2025-05-13 15:19:57+03', NULL);
INSERT INTO education_data.education_data VALUES ('Кадуйская детская школа искусств', 'Кадуйский район', 'Europe/Moscow', 'ул Энтузиастов,д 3', NULL, 'обл Вологодская,р-н Кадуйский,рп Кадуй,ул Энтузиастов,д 3', '{"type": "Point"}', '<p>Школа искусств в поселке Кадуй была создана в 1972 году. Здание четырехэтажное. В нем есть концертный зал, административные помещения, классы для групповых и индивидуальных занятий, академический зал для проведения экзаменов, зачетов, конкурсов. Постигая прекрасный мир музыки, танца, красок и форм, здесь учатся около 500 детей в от 4 до 18 лет. </p><p>В школе открыто 5 отделений: музыкальное, хореографическое, изобразительное, раннего эстетического образования, общее эстетическое. Ежегодно учащиеся принимают участие в международных, всероссийских, областных, региональных конкурсах, часто занимая призовые места.</p>', 'https://artschool-kaduy.vlg.muzkult.ru/d/struktura_0', 'artschool.kaduy@mail.ru', '[{"value": "78174251850", "comment": ""}, {"value": "78174252225", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/d55cb9fd17bf22163f0bea815df3f0be.jpg", "title": "Школа искусств.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «Кадуйская школа искусств»', 'Кадуйский район', 'Europe/Moscow', 'ул Энтузиастов,д 3А', NULL, 'обл Вологодская,р-н Кадуйский,рп Кадуй,ул Энтузиастов,д 3А', NULL, 3510003205, 'mincult', 'Кадуйский район', 'Europe/Moscow', '[{"network":"vk","name":"Наталья Кумакова","networkId":"33381938","isPersonal":true,"updateDate":"2021-05-17T12:45:42Z","createDate":"2021-05-17T12:45:42Z","accountId":37829,"postingGroupId":34459},{"network":"ok","name":"Культура.Кадуй","networkId":"61103236120724","updateDate":"2022-05-18T05:53:22Z","createDate":"2022-05-18T05:53:22Z","accountId":41766,"postingGroupId":36809}]', 16786, '[{"name": "Современное искусство"}, {"name": "Музыка"}, {"name": "Доступная среда"}, {"name": "Классическое искусство"}, {"name": "Для детей"}, {"name": "Дополнительное образование"}]', NULL, '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 60397, '[{"url":"https://www.culture.ru/institutes/61287/kaduiskaya-detskaya-shkola-iskusstv","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/kaduy/obrazovatelnye-uchrezhdeniya/65742pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=9f4cb163-f611-45d5-909c-0d3e9c75a3d6&shareType=venue","serviceName":"ФанТам"}]', 60397, NULL, NULL, NULL, '2022-01-31 14:44:22+03', '2025-08-08 12:12:23+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств города Белозерска', 'Белозерский район', 'Europe/Moscow', 'пр-кт Советский,д 45', NULL, 'обл Вологодская,р-н Белозерский,г Белозерск,пр-кт Советский,д 45', '{"type": "Point"}', '<p><span>Белозерская детская школа искусств была основана в </span><span>1990<span> году (ранее – музыкальная школа, открытая в 1962 году). </span></span><span>Сегодня в ней обучается более 230 детей в возрасте от 3 до 18 лет, работают 11 преподавателей. </span></p> <p><span>Белозерская детская школа искусств реализует программы:</span></p> <ol><li><span> Предпрофессиональные в области<span> </span>искусств </span><span>«Живопись», </span><span>«Фортепиано», </span><span>«Хоровое пение».</span><span></span></li><li><span> Общеразвивающие в области искусств </span><span>«Фортепиано», </span><span>«Клавишный синтезатор», </span><span>«Хоровое пение», </span><span>«Вокально-эстрадное искусство», </span><span>«Народные инструменты» (гитара, баян), «</span><span>Изобразительное искусство», «</span><span>Хореографическое искусство», «</span><span>Раннее общее эстетическое развитие».</span></li></ol> <p><span> Творческие коллективы школы:</span></p> <ol><li><span>Фольклорный ансамбль «Осенушка». Руководитель – Т. В. Швецова.</span></li><li><span>Вокальный ансамбль<span> </span>«Фантазеры». Руководитель – Т. В. Швецова. </span></li><li><span>Хор «Мечта». Руководитель – В. М. Акимова. </span></li><li><span>Хореографический ансамбль «Карусель». Руководитель – Г. Л. Пирьянен.</span></li><li><span>Ансамбль военно-патриотической песни «Вдохновение». Руководитель – Л. В. Терешина.</span></li></ol>', 'https://bdshi.vlg.muzkult.ru', 'belozerskDSHI@yandex.ru', '[{"value": "79020331296", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/d0f3098f9a805fdaca53a968cfd4d776.jpg", "title": "+.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «Белозерская ДШИ»', 'Белозерский район', 'Europe/Moscow', 'пр-кт Советский,д 45', NULL, 'обл Вологодская,р-н Белозерский,г Белозерск,пр-кт Советский,д 45', NULL, 3503000436, 'mincult', 'Белозерский район', 'Europe/Moscow', NULL, 36494, '[{"name": "Музыка"}, {"name": "Доступная среда"}, {"name": "Классическое искусство"}, {"name": "Для детей"}, {"name": "Дополнительное образование"}]', NULL, '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 82890, '[{"url":"https://www.culture.ru/institutes/95842/detskaya-shkola-iskusstv-goroda-belozerska","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/belozersk/obrazovatelnye-uchrezhdeniya/109823pl","serviceName":"Афиша7"}]', 82890, NULL, NULL, NULL, '2024-02-02 11:58:13+03', '2025-09-16 15:52:49+03', NULL);
INSERT INTO education_data.education_data VALUES ('Дом детства и юношества «Дом знаний»', 'Череповец', 'Europe/Moscow', 'пр-кт Советский,д 54', NULL, 'обл Вологодская,г Череповец,пр-кт Советский,д 54', '{"type": "Point"}', '<p>Муниципальное автономное учреждение дополнительного образования «Дом детства и юношества «Дом знаний» (МАУ ДО ДДиЮ «Дом знаний») является преемником муниципального учреждения «Дом семьи», ранее – Дом работников просвещения, профсоюзный центр культуры учителей, открытый решением Обкома профсоюзов работников народного образования высшей школы и научных учреждений в 1953 году.</p><p>За свою историю он прошел путь от небольшого профильного учреждения – Дома работников просвещения, коллектив которого составлял всего несколько человек, до крупного, известного в городе и за его пределами учреждения дополнительного образования для детей и взрослых.</p><p>Учреждение располагается в здании – памятнике архитектуры XIX – XX веков, в центре города на – Советском (бывшем Воскресенском) проспекте.</p><p>Всего в Доме знаний работает более 100 школ, студий и курсов для всех членов семьи.</p><p>«Дом знаний» – это центр, где осуществляются образовательные программы в области краеведения, художественного образования, иностранных языков, декоративно-прикладного искусства и эстетического воспитания детей. Предоставляются услуги по организации досуга.</p>', 'https://dom-znanij.vlg.muzkult.ru/', 'kn_house@mail.ru', '[{"value": "79110477181"}]', '{"url": "https://all.culture.ru/uploads/5263c8e77ded16fb9af727dbf419080f.jpeg", "title": "20200616_112417.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «ДДиЮ «Дом знаний»', 'Череповец', 'Europe/Moscow', 'пр-кт Советский,54', NULL, 'обл Вологодская,г Череповец,пр-кт Советский,54', NULL, 3528034444, 'mincult', 'Череповец', 'Europe/Moscow', NULL, 20281, '[{"name": "История"}, {"name": "Литература"}, {"name": "Музыка"}, {"name": "Доступная среда"}, {"name": "Для детей"}]', NULL, '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "21:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 61271, '[{"url":"https://www.culture.ru/institutes/61752/dom-detstva-i-yunoshestva-dom-znanii","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/61624pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=1f5e8b71-5cb1-4ebd-adaf-2d35756ef9a6&shareType=venue","serviceName":"ФанТам"}]', 61271, NULL, NULL, NULL, '2022-02-08 16:07:06+03', '2025-09-11 15:57:43+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская школа искусств № 2 им. В. П. Трифонова г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Космонавта Беляева,д 22а', 'авт. № 27, 12, 49, 20, 28', 'обл Вологодская,г Вологда,ул Космонавта Беляева,д 22а', '{"type": "Point"}', '<p> В 1961 г. появился филиал, которому в перспективном промышленном районе Вологды, конечно, суждено было очень скоро стать самостоятельным учебным заведением – детской музыкальной школой № 2. 1 сентября 1963 года дети пришли в только что открывшуюся школу, у которой пока еще не было здания. Была четырехкомнатная квартира в доме по улице Беляева, но это не могло омрачить радости события. </p><p>С каждым годом учеников становилось все больше, и места уже не хватало: занимались и в учебных классах школ № 7 и № 21, и в клубе «Звездочка», и в клубе льнокомбината. </p><p>В настоящее время в Вологодской детской школе искусств пять отделений: фортепианное, оркестровое (скрипка, виолончель, духовые инструменты), народное (баян, аккордеон, домра, балалайка, гитара), изобразительного искусства, раннего эстетического развития для детей 3–4 лет. Контингент учащихся составляет 712 человек, 464 из них посещают музыкальные отделения, 140 – отделение изобразительного искусства и 108 – отделение раннего эстетического развития. </p><p>По вопросам обучения и концертной деятельности учреждение активно сотрудничает с образовательными и культурно-досуговыми учреждениями микрорайона. Школа является неотъемлемой частью культурной жизни города Вологды, бережно хранит и развивает высокие традиции российской культуры, чтит память об основателе и первом директоре школы Василии Павловиче Трифонове. </p>', 'http://dmsh-trifonova.ru', 'art_2001@mail.ru', '[{"value": "78172730870", "comment": ""}, {"value": "78172731511", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/fdd71013701ce0b2f00ee5bb62bf847d.jpg", "title": "LSD5zlQBXxtJCvBC6wXpV1cx0tYkvO5h2CM31llH4x6soDBKALZfWC5L7H0MNbMFnJznlbhGjwLCpfcVPpmjjd8M.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУДО «ДШИ №2 им. В. П. Трифонова» г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Беляева,д 22А', NULL, 'обл Вологодская,г Вологда,ул Беляева,д 22А', NULL, 3525086444, 'mincult', 'Вологда', 'Europe/Moscow', '[{"network":"vk","name":"Детская школа искусств №2 им. В.П. Трифонова","networkId":"183412157","updateDate":"2021-05-11T07:10:06Z","createDate":"2021-05-11T07:10:06Z","accountId":37688,"postingGroupId":34363}]', 16832, '[{"name": "Искусство"}, {"name": "Музыка"}, {"name": "Доступная среда"}, {"name": "Для молодежи"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 56729, '[{"url":"https://www.culture.ru/institutes/55662/detskaya-shkola-iskusstv-2-im-v-p-trifonova-g-vologdy","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/74599pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=7b0af3c8-66af-4e4f-a418-42c01df62c4d&shareType=venue","serviceName":"ФанТам"}]', 56729, NULL, NULL, NULL, '2021-09-06 15:03:45+03', '2025-09-16 17:15:36+03', NULL);
INSERT INTO education_data.education_data VALUES ('Вологодский областной колледж искусств', 'Вологда', 'Europe/Moscow', 'ул Горького,д 105', NULL, 'обл Вологодская,г Вологда,ул Горького,д 105', '{"type": "Point"}', '<p>Вологодский областной колледж искусств – старейшее профессиональное учебное заведение на севере России. Любовь к музыке, сохранение и приумножение традиций прошлого, преданность профессии, талант, мастерство педагогов сделали его известным далеко за пределами Вологодчины. </p><p> Созидательная работа коллектива колледжа, направленная на совершенствование учебных программ, концертная, музыкально-просветительская деятельность, профессиональные достижения студентов и выпускников сделали его известным далеко за пределами области.   </p><p>Вологодский областной колледж искусств сегодня – современное, активно развивающееся учебное заведение, воспитывающее музыкантов широкого кругозора, дающее хорошую профессиональную подготовку своим выпускникам. </p>', 'http://www.muscollege.ru', 'vologdamusic@yandex.ru', '[{"value": "78172272456", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/d164aa52b2d08014377a5d95d7b8e3f1.jpg", "title": "main_college.jpg"}', NULL, NULL, 'Образовательные учреждения', 'БПОУ «Вологодский областной колледж искусств»', 'Вологда', 'Europe/Moscow', 'ул Горького,д 105', NULL, 'обл Вологодская,г Вологда,ул Горького,д 105', NULL, 3525048819, 'mincult', 'Вологодская область', 'Europe/Moscow', NULL, 7555, '[{"name": "Искусство"}, {"name": "Музыка"}, {"name": "Доступная среда"}, {"name": "Колледж"}]', NULL, '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', '{"to": "18:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 12653, '[{"url":"https://www.culture.ru/institutes/37881/vologodskii-oblastnoi-kolledzh-iskusstv","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/97749pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=a9595800-034f-4766-a492-5a1ff4e91d95&shareType=venue","serviceName":"ФанТам"}]', 12653, NULL, NULL, NULL, '2015-07-31 16:18:47+03', '2025-09-04 09:35:56+03', NULL);
INSERT INTO education_data.education_data VALUES ('Детская музыкальная школа № 4 г. Вологды', 'Вологда', 'Europe/Moscow', 'ул Ленинградская,д 28', NULL, 'обл Вологодская,г Вологда,ул Ленинградская,д 28', '{"type": "Point"}', '<p> Торжественное открытие детской музыкальной школы № 4 города Вологды состоялось 4 ноября 1973 года. </p><p>Школа реализует дополнительные общеразвивающие и предпрофессиональные программы дополнительного образования художественно-эстетической направленности: инструментальное исполнительство (фортепиано, баян, аккордеон, домра, балалайка, гитара, гармонь, скрипка, виолончель, флейта, кларнет), вокально-хоровое исполнительство, фольклорно-этнографическое, театральное творчество. Прием в музыкальную школу осуществляется согласно учебному плану на пятилетний или семилетний курс обучения.</p><p>В настоящее время звание «Народный самодеятельный коллектив» имеют пять коллективов школы:<span> хоровой ансамбль «</span><span>As-</span><span>соль», </span><span>вокальный ансамбль «Настроение»; звание «О</span><span>бразцовый художественный коллектив» – вокальный ансамбль «Соловушки», </span><span>оркестр русских народных инструментов, </span><span>фольклорный ансамбль «Жаровлика».</span></p><p><span> </span>Жизнь школы интересна и многогранна: победы в конкурсах и фестивалях, выступления на различных концертных площадках города, разнообразие внеклассных мероприятий и постоянное общение с миром музыки!</p>', 'http://musicschool4.ru', 'dmch4@mail.ru', '[{"value": "78172728794"}, {"value": "78172728794"}]', '{"url": "https://all.culture.ru/uploads/645cb5991abbb74e7f5e350103e5e5aa.jpg", "title": "Фасад Ленинградская,28.jpg"}', NULL, NULL, 'Образовательные учреждения', 'МБУ ДО «Детская музыкальная школа № 4» г.Вологды', 'Вологда', 'Europe/Moscow', 'ул Ленинградская,д 28', NULL, 'обл Вологодская,г Вологда,ул Ленинградская,д 28', NULL, 3525086116, 'mincult', 'Вологодский район', 'Europe/Moscow', '[{"network":"vk","name":"Детская музыкальная школа №4(Вологда)","networkId":"193440980","updateDate":"2021-04-06T15:28:55Z","createDate":"2021-04-06T15:28:55Z","accountId":36524,"postingGroupId":33382}]', 20398, '[{"name": "Доступная среда"}, {"name": "Для молодежи"}, {"name": "Дополнительное образование"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 36898, '[{"url":"https://www.culture.ru/institutes/58753/detskaya-muzykalnaya-shkola-4-g-vologdy","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/vologda/obrazovatelnye-uchrezhdeniya/73715pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=6b340c79-590e-42c1-a6d3-6855048cbe33&shareType=venue","serviceName":"ФанТам"}]', 36898, NULL, NULL, NULL, '2018-12-11 07:58:41+03', '2025-10-20 18:14:17+03', NULL);
INSERT INTO education_data.education_data VALUES ('Училище искусств и художественных ремесел им. В. Верещагина', 'Череповец', 'Europe/Moscow', 'ул Сталеваров,д 34А', NULL, 'обл Вологодская,г Череповец,ул Сталеваров,д 34А', '{"type": "Point"}', '<p>Череповецкое училище искусств и художественных ремесел им. В. В. Верещагина – одна из крупнейших профессиональных образовательных организаций Северо-Запада России, осуществляющих подготовку специалистов среднего звена для сферы культуры и искусства.</p><p>Свою историю училище ведет с открытия музыкального отделения летом 1969 года, когда был подписан приказ о создании нового самостоятельного учебного заведения в Череповце. Большую роль в становлении тогда еще музыкального училища сыграл заслуженный работник культуры России Е. А. Колесников. </p><p>Первыми преподавателями стали опытные музыканты из единственной тогда в городе музыкальной школы, коллективов самодеятельности и молодые выпускники консерваторий, музыкальных вузов и училищ страны. С первых лет работы молодой коллектив заложил традиции в культурной жизни города и области, которым следует и сегодня.</p>', 'http://art-college.ru', 'art.college@mail.ru', '[{"value": "78202576783", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/5154f36be78dec097c6a22a100725393.jpg", "title": "ФАСАД УЧИЛИЩА ИСКУССТВ.jpg"}', NULL, NULL, 'Образовательные учреждения', 'БПОУ «Череповецкое областное училище искусств и художественных ремесел им. В. В. Верещагина»', 'Череповец', 'Europe/Moscow', 'ул Сталеваров,д 34А', NULL, 'обл Вологодская,г Череповец,ул Сталеваров,д 34А', NULL, 3528034892, 'mincult', 'Вологодская область', 'Europe/Moscow', '[{"network":"vk","name":"КУДА ИДТИ УЧИТЬСЯ ? (г. Череповец)","networkId":"97256138","updateDate":"2018-04-03T09:00:51Z","createDate":"2018-04-03T09:00:51Z","accountId":18923,"postingGroupId":18150},{"network":"vk","name":"Международный конкурс \"СЕВЕРНАЯ РАПСОДИЯ\"","networkId":"112427095","updateDate":"2018-04-03T09:01:11Z","createDate":"2018-04-03T09:01:11Z","accountId":18923,"postingGroupId":18153},{"network":"vk","name":"Объединение студентов (Училище искусств)","networkId":"128110515","updateDate":"2018-04-03T09:00:58Z","createDate":"2018-04-03T09:00:58Z","accountId":18923,"postingGroupId":18151},{"network":"vk","name":"Проект \"Доступная Классика\" Череповец","networkId":"134566286","updateDate":"2018-04-03T09:01:08Z","createDate":"2018-04-03T09:01:08Z","accountId":18923,"postingGroupId":18152},{"network":"vk","name":"Училище искусств им. В.В. Верещагина","networkId":"1261949","updateDate":"2017-12-27T09:13:12Z","createDate":"2017-12-27T09:13:12Z","accountId":18923,"postingGroupId":16681},{"network":"vk","name":"Школа при УчилищеИскусств (Отдел ДОП образовани)","networkId":"102295374","updateDate":"2017-12-27T09:13:29Z","createDate":"2017-12-27T09:13:29Z","accountId":18923,"postingGroupId":16682}]', 7554, '[{"name": "Оркестр"}, {"name": "Классическая музыка"}, {"name": "Доступная среда"}, {"name": "Колледж"}, {"name": "Классическое искусство"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 12656, '[{"url":"https://www.culture.ru/institutes/37880/uchilishe-iskusstv-i-khudozhestvennykh-remesel-im-v-vereshagina","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/cherepovec/obrazovatelnye-uchrezhdeniya/90970pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=da5e0113-4b7c-4996-bfc0-bb21d7116d08&shareType=venue","serviceName":"ФанТам"}]', 12656, NULL, NULL, NULL, '2015-07-31 16:20:31+03', '2026-02-18 07:10:35+03', NULL);
INSERT INTO education_data.education_data VALUES ('Сямженская детская школа искусств', 'Сямженский район', 'Europe/Moscow', 'ул Славянская,д 1', NULL, 'обл Вологодская,р-н Сямженский,с Сямжа,ул Славянская,д 1', '{"type": "Point"}', '<p><span>Сямженская детская школа искусств располагается в просторном здании, где есть специально оборудованные классы для музыкального отделения, хореографии, изобразительного искусства, декоративно-прикладного творчества, отдельный кабинет для теоретических дисциплин, концертный зал.</span></p><p style="text-align:justify"><span></span></p><p><span>В настоящее время в школе работает стабильный профессиональный педагогический коллектив. Из 8 преподавателей 3 человека имеют высшее образование, 5 человек – среднее специальное, 6 преподавателям присвоена высшая квалификационная категория. </span><span>В школе работают 6 отделений: музыкальное, хореографическое, художественное, декоративно-прикладное, театральное, эстетическое. </span><span>За период существования школу окончило более 500 учащихся, многие<span> </span>из которых выбрали свой дальнейший путь, связанный с искусством, культурой и педагогикой.</span></p> <p><span>ДШИ гордится своими выпускниками, среди них Светлана Сигалева и Леонид Егоров (уже преподают в этой школе), Марина Каштанова, Яна Загоскина, Надя Пантина, Маша и Катя Староверовы, Таня Самойлова, Лида Чеканова, Андрей Пахомов, Наташа Леонова и др.</span></p><p></p><p></p><p></p><p>Преподаватели стараются работать так, чтобы школа стала очагом вдохновенья и творчества, где открывается для детских сердец прекрасный мир под названием искусство!</p>', NULL, NULL, NULL, '{"url": "https://all.culture.ru/uploads/8602f7ac8ef9c5779d359e9b0c8934a6.png", "title": "фото 1.png"}', NULL, NULL, 'Образовательные учреждения', 'БУ ДО «Сямженская ДШИ»', 'Сямженский район', 'Europe/Moscow', 'ул Славянская,д 1', NULL, 'обл Вологодская,р-н Сямженский,с Сямжа,ул Славянская,д 1', NULL, 3516001571, 'mincult', 'Сямженский район', 'Europe/Moscow', NULL, 17536, '[{"name": "Искусство"}, {"name": "Музыка"}, {"name": "Классическое искусство"}, {"name": "Доступная среда"}]', NULL, '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', '{"to": "20:00:00", "from": "08:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 62596, '[{"url":"https://www.culture.ru/institutes/65450/syamzhenskaya-detskaya-shkola-iskusstv","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/syamzha/obrazovatelnye-uchrezhdeniya/68353pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=9db1bc24-1c39-4e95-9894-cb4ca878dc01&shareType=venue","serviceName":"ФанТам"}]', 62596, NULL, NULL, NULL, '2022-02-17 11:18:04+03', '2026-04-06 14:00:52+03', NULL);
INSERT INTO education_data.education_data VALUES ('Кичменгско-Городецкая детская школа искусств им. Н. П. Парушева', 'Кичменгско-Городецкий район', 'Europe/Moscow', 'ул Советская,д 11', NULL, 'обл Вологодская,р-н Кичменгско-Городецкий,с Кичменгский Городок,ул Советская,д 11', '{"type": "Point"}', '<p><span>Кичменгско-Городецкая детская школа искусств им. Н. П. Парушева была основана в 1966 году. </span></p> <p><span>В школе реализуются предпрофессиональные программы: «Живопись», «Фортепиано», «Народные инструменты» (баян, аккордеон, гармонь), «</span><span>Хореографическое творчество»</span><span>. </span><span>Осуществляется реализация дополнительных разворашивающих программ: «Вокальное исполнительство», «Декоративно-прикладное творчество», «Хореографическое искусство», «Сольное пение: профессиональная ориентация», «Общее эстетическое образование», «Раннее эстетическое образование» и «Хореографический ансамбль». </span><span>Активно ведется работа с детьми дошкольного возраста – имеется программа «Раннее эстетическое образование» (для детей 5–7 лет). </span></p> <p><span></span> <span>На базе ДШИ ведут работу творческие коллективы:</span></p> <p><span> </span></p> <ul><li>образцовый хореографический коллектив «Мир детства», руководитель – Никонова Екатерина;</li><li>образцовый хоровой коллектив «Радуга», руководитель – Протасова Любовь;</li><li>младший хор, руководитель – Жаравина Елена;</li><li>образцовый художественный коллектив ансамбль баянистов и аккордеонистов, руководитель – Протасова Любовь;</li><li>вокальный ансамбль эстрадного пения, руководитель – Григорьева Светлана.</li></ul>', 'https://dshi-kichgorod.vlg.muzkult.ru', 'kichgorodokdshi@mail.ru', '[{"value": "78174021100", "comment": ""}, {"value": "79115022298", "comment": ""}]', '{"url": "https://all.culture.ru/uploads/14b1f64ddc9c2801729da676be17d09a.jpeg", "title": "dFRtI-64VrU.jpg"}', '[{"url": "https://all.culture.ru/uploads/374463c548a8f9b324858a8d6993ee10.jpg", "title": "9р.jpg"}, {"url": "https://all.culture.ru/uploads/39df44ddce3952b0b1a045e24fcbf090.jpg", "title": "2р.jpg"}, {"url": "https://all.culture.ru/uploads/8160c095f3de525f94832190bc6ef90c.jpg", "title": "6р.jpg"}, {"url": "https://all.culture.ru/uploads/8a7e62273318ef2219adb0d4df44c353.jpg", "title": "8р.jpg"}, {"url": "https://all.culture.ru/uploads/6c7a505c1b32d3e98b5148b58eb4a5fe.jpg", "title": "4р.jpg"}, {"url": "https://all.culture.ru/uploads/6e88b50754f43a3d0e49f1b0dca90bef.jpg", "title": "5р.jpg"}]', NULL, 'Образовательные учреждения', 'МБУДО «Кичменгско-Городецкая ДШИ им. Н.П. Парушева»', 'Кичменгско-Городецкий район', 'Europe/Moscow', 'ул Советская,д 11', NULL, 'обл Вологодская,р-н Кичменгско-Городецкий,с Кичменгский Городок,ул Советская,д 11', NULL, 3512002574, 'mincult', 'Кичменгско-Городецкий район', 'Europe/Moscow', '[{"network":"vk","name":"Елена Снегова","networkId":"64251256","updateDate":"2022-11-18T13:38:35Z","createDate":"2022-11-18T13:38:35Z","accountId":43108,"postingGroupId":37296},{"network":"vk","name":"Кичменгско-Городецкая ДШИ им.Н.П.Парушева","networkId":"15584801","updateDate":"2016-11-07T12:05:52Z","createDate":"2016-11-07T12:05:52Z","accountId":11050,"postingGroupId":9456},{"network":"vk","name":"Ольга Ладина","networkId":"16523711","isPersonal":true,"updateDate":"2016-11-07T12:06:05Z","createDate":"2016-11-07T12:06:05Z","accountId":11050,"postingGroupId":9457}]', 13362, '[{"name": "Искусство"}, {"name": "Музыка"}, {"name": "Доступная среда"}, {"name": "Для детей"}]', NULL, '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "20:00:00", "from": "09:00:00"}', '{"to": "16:00:00", "from": "09:00:00"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 59892, '[{"url":"https://www.culture.ru/institutes/60732/kichmengsko-gorodeckaya-detskaya-shkola-iskusstv-im-n-p-parusheva","serviceName":"Культура.рф"},{"url":"https://afisha7.ru/kichmengskiy-gorodok/obrazovatelnye-uchrezhdeniya/60034pl","serviceName":"Афиша7"},{"url":"https://map.funtam.ru/offer/poi?showMainEvent=false&shareId=2a19161d-dd5f-4860-a1de-e05187a6ce3c&shareType=venue","serviceName":"ФанТам"}]', 59892, NULL, NULL, NULL, '2022-01-25 17:06:15+03', '2026-04-03 15:58:49+03', NULL);


